1	/** A cell's position on an infinite grid, expressed as [x, y]. */
2	export type Cell = [number, number];
3	
4	/** A canonical string form of a cell, used as a Map/Set key. */
5	type CellKey = string;
6	
7	const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;
8	
9	const fromKey = (key: CellKey): Cell => {
10	  const [x, y] = key.split(",").map(Number);
11	  return [x, y];
12	};
13	
14	/** Yields the eight neighbouring cells around the given cell. */
15	function* neighborsOf([x, y]: Cell): Iterable<Cell> {
16	  for (let dx = -1; dx <= 1; dx++) {
17	    for (let dy = -1; dy <= 1; dy++) {
18	      if (dx === 0 && dy === 0) continue;
19	      yield [x + dx, y + dy];
20	    }
21	  }
22	}
23	
24	/**
25	 * Computes the next generation of live cells under Conway's Game of Life rules.
26	 *
27	 * @param liveCells - The currently live cells; any coordinate not listed is dead.
28	 * @returns The live cells in the next generation.
29	 */
30	export function nextGeneration(liveCells: Cell[]): Cell[] {
31	  const liveKeys = new Set(liveCells.map(toKey));
32	  const neighborCounts = new Map<CellKey, number>();
33	
34	  for (const cell of liveCells) {
35	    for (const neighbor of neighborsOf(cell)) {
36	      const key = toKey(neighbor);
37	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
38	    }
39	  }
40	
41	  const isAliveNextGen = (key: CellKey, count: number): boolean =>
42	    count === 3 || (count === 2 && liveKeys.has(key));
43	
44	  const nextGen: Cell[] = [];
45	  for (const [key, count] of neighborCounts) {
46	    if (isAliveNextGen(key, count)) nextGen.push(fromKey(key));
47	  }
48	  return nextGen;
49	}
50

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (each has 1 neighbor) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
17	      new Set(["0,0", "1,0", "0,1", "1,1"])
18	    );
19	  });
20	  it("blinker rotates vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
21	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
22	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
23	      new Set(["-1,1", "0,1", "1,1"])
24	    );
25	  });
26	  it("live cell with 4 neighbors dies (overpopulation) — center of filled 3x3 dies", () => {
27	    const result = nextGeneration([
28	      [0, 0], [1, 0], [2, 0],
29	      [1, 1],
30	      [0, 2], [1, 2], [2, 2],
31	    ]);
32	    const keys = new Set(result.map((c) => c.join(",")));
33	    expect(keys.has("1,1")).toBe(false);
34	  });
35	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction)", () => {
36	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
37	    const keys = new Set(result.map((c) => c.join(",")));
38	    expect(keys.has("1,1")).toBe(true);
39	  });
40	  it.todo("handles negative coordinates correctly");
41	});
